on_write:
let res = #{ action: "Allow" };
if !payload.contains("transaction_id") {
    res.action = "Reject";
    res.reason = "NewSQL records require strict transaction_id tracking";
}
res

on_read:
let res = #{ payload: payload };
if payload.transaction_id == query_key {
    res.match_found = true;
} else {
    res.match_found = false;
}
res
